VALUES
  ('optician-moex-00189', 'optician', 'optician-moex-114-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '自覺式驗光中的那一個步驟，必須在燈光偏暗的環境下檢查較為合適？', '["視力檢查", "傑克森交叉圓柱鏡（JCC）", "紅綠檢查（duochrometest）", "鐘面圖（fanchart）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "90b2828f3433", "answer_pdf_sha1": "d46f08cf362a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00190', 'optician', 'optician-moex-114-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '有關針孔視力的測量，下列何者最為適當？', '["針孔視力（pinholevisualacuity）檢查可以用在病人的矯正視力比20/30 還差的時候", "針孔視力無法幫忙判斷病人的視力下降是否可以藉由鏡片矯正", "透過針孔看視力表，可以減少病人的景深（depthoffocus），因而減少視網膜模糊", "通常測量針孔視力時所用的針孔直徑為2.0mm"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "90b2828f3433", "answer_pdf_sha1": "d46f08cf362a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00191', 'optician', 'optician-moex-114-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '利用傑克森交叉圓柱鏡（JCC）尋找受測者初軸時，JCC鏡片放上-0.50DC移除-0.25DS，P對180度時， 紅點視標較清楚；對45度時，白點視標較清楚；對90度時，白點視標較清楚；對135度時，紅點視標較 清楚。受測者的負散光軸度在下列何處？', '["180度和45度之間", "45度和90度之間", "90度和135度之間", "135度和180度之間"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "90b2828f3433", "answer_pdf_sha1": "d46f08cf362a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00192', 'optician', 'optician-moex-114-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '受測者右眼最佳矯正視力為20/20，左眼最佳矯正視力為20/30，下列那一種平衡方式最適合？', '["垂直稜鏡分離法（verticalprismdissociatedtest）", "交替遮蓋法（alternateocclusiontest）", "垂直稜鏡加紅綠視標法（verticalprismdissociatedduochromebalancetest）", "偏光濾片法（polaroid/vectograph）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "90b2828f3433", "answer_pdf_sha1": "d46f08cf362a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00193', 'optician', 'optician-moex-114-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '他覺式驗光的數值為：-0.75DS/-1.00DC×180，在霧視的情況下利用散光鐘面圖進行散光測量，若被檢者 主述3～9點鐘位置上的線條比較黑，表示此時眼內的成像何者較接近視網膜？', '["水平方向所呈的焦線", "垂直方向所呈的焦線", "被檢者散光所形成的模糊圈", "不一定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "90b2828f3433", "answer_pdf_sha1": "d46f08cf362a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00194', 'optician', 'optician-moex-114-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '當物體移近眼前，會觸發調節（accommodation），關於調節的敘述，下列何者錯誤？', '["調節是指睫狀肌收縮，使水晶體增厚讓因看近而落在視網膜後的影像可以重新聚焦至視網膜上", "當調節發生時，亦會觸發近反射（nearreflex）而使瞳孔放大", "當雙眼同時看近物時，亦會同時產生調節性內聚（accommodativeconvergence）", "AC/ARatio即是每做出1D之調節可誘發多少程度之調節性內聚之比值"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "90b2828f3433", "answer_pdf_sha1": "d46f08cf362a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00195', 'optician', 'optician-moex-114-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '一位30歲女性患者主述看近模糊，下列何者錯誤？', '["患者過去病史有服用鎮靜安眠藥物可能引起看近模糊", "患者若有近視，可使用多焦鏡片改善", "患者調節幅度過早下降，可能是神經系統的疾病，例如腦炎或腦部外傷造成", "調節不足（accommodationinsufficiency）常見原因是未被發現的（隱性）遠視和矯正不足的近視"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "90b2828f3433", "answer_pdf_sha1": "d46f08cf362a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 42, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00196', 'optician', 'optician-moex-114-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '關於老花眼（presbyopia）眼鏡驗配的敘述，下列何者正確？', '["依年紀，50歲患者暫定加入度（tentativeADD）為+2.25D", "近用加入度（ADD）與年紀呈現線性相關", "以正負相對調節力（NRA：negativerelativeaccommodationandPRA：positiverelativeaccommodation）調 整加入度（initialtentativeADD）建議使用試鏡架（trialframe）", "測量65歲患者的調節幅度（accommodativeamplitude）改以焦深（depthoffocus）取代"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "90b2828f3433", "answer_pdf_sha1": "d46f08cf362a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 43, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00197', 'optician', 'optician-moex-114-148c1cdf', 'sub-optician-04', NULL, 'single_choice', 'Nott 動態視網膜檢影術（Nott dynamic retinoscopy）是一種檢影距離與視標工作距離不同的調節精準度 （accommodationaccuracy）檢查方法。假定網膜檢影鏡固定於50cm處，視標置於40cm處時可觀察到中 和（Neutrality），則應記錄為下列何者？', '["lag+0.50D", "lag+0.75D", "lead-0.50D", "lead-0.75D"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "90b2828f3433", "answer_pdf_sha1": "d46f08cf362a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00198', 'optician', 'optician-moex-114-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '在一位雙眼正視眼且裸視的調節近點皆在前 20cm 的被檢者右眼前放置+2.50 D 與左眼前放置+4.00D 鏡 片，則被檢者的雙眼調節幅度各是多少？', '["右眼2.50DS；左眼1.00DS", "右眼7.50DS；左眼9.00DS", "右眼5.00DS；左眼5.00DS", "右眼2.50DS；左眼4.00DS"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "90b2828f3433", "answer_pdf_sha1": "d46f08cf362a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 45, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
